mapper.insert:
/* 회원등록 */
INSERT INTO member (
	  member_email
	, member_password
	, member_name
	, member_nickname
	, member_role
	, member_phone
	, member_status
	, member_created_at
) VALUES (
	  #{memberEmail}
	, #{memberPassword}
	, #{memberName}
	, #{memberNickname}
	, #{memberRole}
	, #{memberPhone}
	, 1
	, NOW()
);

mapper.update:
		/* 리프레시토큰 수정 */
		UPDATE member
        SET 
        	member_refresh_token = #{memberRefreshToken}
        WHERE 
        	member_id = #{memberId};
